class Solution:
    def decimalRepresentation(self, n):
        s = str(n)
        L = len(s)
        res = []
        for idx, ch in enumerate(s):
            d = int(ch)
            if d != 0:
                power = L - 1 - idx
                res.append(d * (10 ** power))
        return res

