var decimalRepresentation = function(n) {
    const comps = [];
    let place = 1;
    while (n > 0) {
        const d = n % 10;
        if (d !== 0) comps.push(d * place);
        place *= 10;
        n = Math.floor(n / 10);
    }
    comps.reverse();
    return comps;
};
